import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class JsonWriter_value_Test {
  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void value_writesLongValue_correctly() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);

    // stub writeDeferredName and beforeValue to do nothing (private methods)
    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    JsonWriter returned = spyWriter.value(123456789L);

    assertSame(spyWriter, returned);
    assertEquals("123456789", stringWriter.toString());

    verify(spyWriter).writeDeferredName();
    verify(spyWriter).beforeValue();
  }

  @Test
  public void value_invokesPrivateWriteDeferredName_andBeforeValue() throws Throwable {
    // Use reflection to invoke private methods to ensure they exist and callable
    Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredName.setAccessible(true);
    Method beforeValue = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValue.setAccessible(true);

    // invoke private methods without error
    writeDeferredName.invoke(jsonWriter);
    beforeValue.invoke(jsonWriter);
  }

  @Test
  public void value_withNegativeLong_writesCorrectString() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);

    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    spyWriter.value(-9876543210L);

    assertEquals("-9876543210", stringWriter.toString());
  }

  @Test
  public void value_withZero_writesZero() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);

    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    spyWriter.value(0L);

    assertEquals("0", stringWriter.toString());
  }
}
